components.SendMoneyFlow:
export default function SendMoneyFlow() {
  const [step, setStep] = React.useState<"pick"|"amount"|"review"|"done">("pick");
  const [payees, setPayees] = React.useState<any[]>([]);
  const [selectedPayee, setSelectedPayee] = React.useState<any>(null);
  const [amountDollars, setAmountDollars] = React.useState("");
  const [memo, setMemo] = React.useState("");
  const [accounts, setAccounts] = React.useState<any[]>([]);
  const [checkingAccount, setCheckingAccount] = React.useState<any>(null);
  const [status, setStatus] = React.useState<"idle"|"pending"|"approved"|"error">("idle");
  const [errorMsg, setErrorMsg] = React.useState("");

  React.useEffect(() => {
    (async () => {
      const p = await tools.host_listPayees({});
      setPayees(p.data || p.payees || p || []);
      const a = await tools.host_listAccounts({});
      const accs = a.data || a.accounts || a || [];
      setAccounts(accs);
      const checking = accs.find((ac: any) =>
        (ac.type || ac.accountType || "").toLowerCase().includes("check") ||
        (ac.name || "").toLowerCase().includes("check")
      ) || accs[0];
      setCheckingAccount(checking);
    })();
  }, []);

  const amountCents = Math.round(parseFloat(amountDollars || "0") * 100);
  const amountValid = !isNaN(amountCents) && amountCents > 0;

  async function handleSend() {
    setStatus("pending");
    setErrorMsg("");
    try {
      const result = await tools.host_transferMoney({
        amount: amountCents,
        recipient_name: selectedPayee?.name || selectedPayee?.payeeName || "",
        memo: memo,
      });
      if (result && result.status === "pending-approval") {
        setStatus("pending");
      } else {
        setStatus("approved");
        setStep("done");
      }
    } catch (e: any) {
      setStatus("error");
      setErrorMsg(e?.message || "Something went wrong. Please try again.");
    }
  }

  const containerStyle: React.CSSProperties = {
    maxWidth: 480,
    margin: "0 auto",
    padding: "32px 16px",
    fontFamily: "var(--vendo-font-family)",
    color: "var(--vendo-color-text)",
  };

  const surfaceStyle: React.CSSProperties = {
    background: "var(--vendo-color-surface)",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-medium)",
    padding: "28px 24px",
  };

  const labelStyle: React.CSSProperties = {
    fontSize: 12,
    fontWeight: 600,
    letterSpacing: "0.06em",
    textTransform: "uppercase",
    color: "var(--vendo-color-muted)",
    marginBottom: 8,
  };

  const inputStyle: React.CSSProperties = {
    width: "100%",
    boxSizing: "border-box",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-small)",
    padding: "10px 12px",
    fontSize: 15,
    fontFamily: "var(--vendo-font-family)",
    color: "var(--vendo-color-text)",
    background: "var(--vendo-color-surface)",
    outline: "none",
  };

  const primaryBtn: React.CSSProperties = {
    width: "100%",
    padding: "13px 0",
    background: "var(--vendo-color-accent)",
    color: "var(--vendo-color-accent-text)",
    border: "none",
    borderRadius: "var(--vendo-radius-small)",
    fontSize: 15,
    fontWeight: 600,
    cursor: "pointer",
    marginTop: 24,
  };

  const ghostBtn: React.CSSProperties = {
    background: "none",
    border: "none",
    color: "var(--vendo-color-muted)",
    fontSize: 14,
    cursor: "pointer",
    padding: "8px 0",
    marginTop: 8,
    width: "100%",
    textAlign: "center",
  };

  const payeeCardStyle = (selected: boolean): React.CSSProperties => ({
    display: "flex",
    alignItems: "center",
    gap: 12,
    padding: "12px 14px",
    border: selected ? "1.5px solid var(--vendo-color-accent)" : "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-small)",
    cursor: "pointer",
    background: selected ? "#F5F5F4" : "var(--vendo-color-surface)",
    marginBottom: 8,
    transition: "border 0.15s",
  });

  const avatarStyle: React.CSSProperties = {
    width: 38,
    height: 38,
    borderRadius: "50%",
    background: "var(--vendo-color-accent)",
    color: "var(--vendo-color-accent-text)",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontWeight: 700,
    fontSize: 15,
    flexShrink: 0,
  };

  const rowStyle: React.CSSProperties = {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "10px 0",
    borderBottom: "1px solid var(--vendo-color-border)",
  };

  const stepIndicator = (
    <div style={{ display: "flex", gap: 6, marginBottom: 28, justifyContent: "center" }}>
      {(["pick","amount","review"] as const).map((s, i) => (
        <div key={s} style={{
          width: 28, height: 4, borderRadius: 2,
          background: (step === "pick" && i === 0) || (step === "amount" && i <= 1) || (step === "review" && i <= 2) || step === "done"
            ? "var(--vendo-color-accent)" : "var(--vendo-color-border)",
          transition: "background 0.2s",
        }}/>
      ))}
    </div>
  );

  if (step === "done") {
    return (
      <div style={containerStyle}>
        <div style={surfaceStyle}>
          <div style={{ textAlign: "center", padding: "16px 0 8px" }}>
            <div style={{ fontSize: 44, marginBottom: 16 }}>✓</div>
            <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 8 }}>
              {status === "pending" ? "Awaiting approval" : "Sent!"}
            </div>
            <div style={{ color: "var(--vendo-color-muted)", fontSize: 15, marginBottom: 24 }}>
              {status === "pending"
                ? "Your transfer is pending approval. We'll notify you once it's confirmed."
                : `${fmt.money(amountCents)} sent to ${selectedPayee?.name || selectedPayee?.payeeName || "payee"}.`}
            </div>
            <div style={{ fontSize: 28, fontWeight: 700, marginBottom: 4 }}>
              {fmt.money(amountCents)}
            </div>
            <div style={{ color: "var(--vendo-color-muted)", fontSize: 14, marginBottom: 24 }}>
              to {selectedPayee?.name || selectedPayee?.payeeName}
            </div>
            {memo ? (
              <div style={{ color: "var(--vendo-color-muted)", fontSize: 14, fontStyle: "italic", marginBottom: 24 }}>
                "{memo}"
              </div>
            ) : null}
            <button style={primaryBtn} onClick={() => {
              setStep("pick");
              setSelectedPayee(null);
              setAmountDollars("");
              setMemo("");
              setStatus("idle");
            }}>
              Send another
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (step === "pick") {
    return (
      <div style={containerStyle}>
        <div style={{ marginBottom: 24 }}>
          <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 4 }}>Send money</div>
          <div style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>Choose a saved payee</div>
        </div>
        {stepIndicator}
        <div style={surfaceStyle}>
          {payees.length === 0 ? (
            <div style={{ color: "var(--vendo-color-muted)", textAlign: "center", padding: "24px 0" }}>
              No saved payees found.
            </div>
          ) : payees.map((p: any) => {
            const name = p.name || p.payeeName || "Payee";
            const initials = name.split(" ").map((w: string) => w[0]).join("").slice(0,2).toUpperCase();
            const isSelected = selectedPayee?.id === p.id;
            return (
              <div key={p.id} style={payeeCardStyle(isSelected)} onClick={() => setSelectedPayee(p)}>
                <div style={avatarStyle}>{initials}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600, fontSize: 15 }}>{name}</div>
                  {p.accountNumber || p.email || p.bank ? (
                    <div style={{ color: "var(--vendo-color-muted)", fontSize: 13 }}>
                      {p.bank || p.email || (p.accountNumber ? `••••${String(p.accountNumber).slice(-4)}` : "")}
                    </div>
                  ) : null}
                </div>
                {isSelected && (
                  <div style={{ color: "var(--vendo-color-accent)", fontWeight: 700, fontSize: 18 }}>✓</div>
                )}
              </div>
            );
          })}
          <button
            style={{ ...primaryBtn, opacity: selectedPayee ? 1 : 0.4, cursor: selectedPayee ? "pointer" : "not-allowed" }}
            disabled={!selectedPayee}
            onClick={() => selectedPayee && setStep("amount")}
          >
            Continue
          </button>
        </div>
      </div>
    );
  }

  if (step === "amount") {
    return (
      <div style={containerStyle}>
        <div style={{ marginBottom: 24 }}>
          <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 4 }}>Send money</div>
          <div style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>
            To {selectedPayee?.name || selectedPayee?.payeeName}
          </div>
        </div>
        {stepIndicator}
        <div style={surfaceStyle}>
          <div style={{ textAlign: "center", marginBottom: 28 }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 4 }}>
              <span style={{ fontSize: 32, fontWeight: 300, color: "var(--vendo-color-muted)" }}>$</span>
              <input
                type="number"
                min="0.01"
                step="0.01"
                placeholder="0.00"
                value={amountDollars}
                onChange={e => setAmountDollars(e.target.value)}
                style={{
                  border: "none",
                  borderBottom: "2px solid var(--vendo-color-accent)",
                  borderRadius: 0,
                  fontSize: 40,
                  fontWeight: 700,
                  width: 180,
                  textAlign: "center",
                  outline: "none",
                  background: "transparent",
                  color: "var(--vendo-color-text)",
                  fontFamily: "var(--vendo-font-family)",
                }}
              />
            </div>
            {checkingAccount && (
              <div style={{ color: "var(--vendo-color-muted)", fontSize: 13, marginTop: 10 }}>
                From {checkingAccount.name || "Checking"} · Balance {fmt.money(checkingAccount.balanceCents || checkingAccount.balance || 0)}
              </div>
            )}
          </div>
          <div style={{ marginBottom: 20 }}>
            <div style={labelStyle}>Note (optional)</div>
            <input
              type="text"
              placeholder="What's it for?"
              value={memo}
              onChange={e => setMemo(e.target.value)}
              style={inputStyle}
            />
          </div>
          <button
            style={{ ...primaryBtn, opacity: amountValid ? 1 : 0.4, cursor: amountValid ? "pointer" : "not-allowed" }}
            disabled={!amountValid}
            onClick={() => amountValid && setStep("review")}
          >
            Review
          </button>
          <button style={ghostBtn} onClick={() => setStep("pick")}>← Back</button>
        </div>
      </div>
    );
  }

  return (
    <div style={containerStyle}>
      <div style={{ marginBottom: 24 }}>
        <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 4 }}>Review transfer</div>
        <div style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>Confirm the details before sending</div>
      </div>
      {stepIndicator}
      <div style={surfaceStyle}>
        <div style={{ textAlign: "center", marginBottom: 28 }}>
          <div style={{ fontSize: 40, fontWeight: 700, marginBottom: 4 }}>{fmt.money(amountCents)}</div>
          <div style={{ color: "var(--vendo-color-muted)", fontSize: 15 }}>
            to {selectedPayee?.name || selectedPayee?.payeeName}
          </div>
        </div>
        <div>
          <div style={rowStyle}>
            <span style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>From</span>
            <span style={{ fontWeight: 500, fontSize: 14 }}>{checkingAccount?.name || "Checking"}</span>
          </div>
          <div style={rowStyle}>
            <span style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>To</span>
            <span style={{ fontWeight: 500, fontSize: 14 }}>{selectedPayee?.name || selectedPayee?.payeeName}</span>
          </div>
          <div style={rowStyle}>
            <span style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>Amount</span>
            <span style={{ fontWeight: 600, fontSize: 14 }}>{fmt.money(amountCents)}</span>
          </div>
          {memo ? (
            <div style={{ ...rowStyle, borderBottom: "none" }}>
              <span style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>Note</span>
              <span style={{ fontWeight: 500, fontSize: 14, maxWidth: 220, textAlign: "right" }}>{memo}</span>
            </div>
          ) : (
            <div style={{ ...rowStyle, borderBottom: "none" }}>
              <span style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>Note</span>
              <span style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>—</span>
            </div>
          )}
        </div>
        {errorMsg ? (
          <div style={{ color: "var(--vendo-color-danger)", fontSize: 14, marginTop: 16, textAlign: "center" }}>
            {errorMsg}
          </div>
        ) : null}
        <button
          style={{ ...primaryBtn, opacity: status === "pending" ? 0.6 : 1, cursor: status === "pending" ? "not-allowed" : "pointer" }}
          disabled={status === "pending"}
          onClick={handleSend}
        >
          {status === "pending" ? "Sending…" : "Send money"}
        </button>
        <button style={ghostBtn} onClick={() => setStep("amount")}>← Back</button>
      </div>
    </div>
  );
}
